import pandas as pd
import numpy as np
from datetime import datetime, timedelta
import warnings
warnings.filterwarnings('ignore')

print("=" * 60)
print("CANADIAN RETAIL DEMAND FORECASTING")
print("Portfolio Project | Bhavithra SS")
